function example() {
  if (true) {
    var message = 'hello'; // declared inside a block
  }
  console.log(message); // 'hello' — leaks out of the if block!
}
example();

function example() {
  if (true) {
    let message = 'hello';
    const greeting = 'hi';
  }
  console.log(message);  // ReferenceError: message is not defined
  console.log(greeting); // ReferenceError: greeting is not defined
}

const count = 0;
count = 1; // ❌ TypeError: Assignment to constant variable

const user = { name: 'Alice' };
user.name = 'Bob';   // ✅ Allowed — mutating the object's property
user = { name: 'Carol' }; // ❌ TypeError — reassigning the variable itself

const colors = ['red', 'blue'];
colors.push('green'); // ✅ Allowed — mutating the array
colors = ['red'];     // ❌ TypeError — reassigning the variable itself

// var is hoisted and initialized to undefined
console.log(score); // undefined (no error)
var score = 10;
console.log(score); // 10

// let is in the TDZ until the declaration is reached
console.log(name); // ❌ ReferenceError: Cannot access 'name' before initialization
let name = 'Alice';

// const behaves the same as let
console.log(PI); // ❌ ReferenceError
const PI = 3.14;

// var can be redeclared — no error, silently overwrites
var username = 'Alice';
var username = 'Bob'; // perfectly legal, no warning
console.log(username); // 'Bob'

// let and const cannot be redeclared in the same scope
let email = 'a@b.com';
let email = 'c@d.com'; // ❌ SyntaxError: Identifier 'email' has already been declared

const port = 3000;
const port = 4000; // ❌ SyntaxError

// ❌ Classic var bug in closures
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Prints: 3, 3, 3
// (by the time setTimeout fires, the loop is done and i === 3)

// ✅ let creates a new binding per iteration
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// Prints: 0, 1, 2 (each closure captures its own i)

// Typical React component — almost everything is const
import { useState } from 'react';

const ITEMS_PER_PAGE = 10; // const: never changes

function ProductList({ products }) {
  const [page, setPage] = useState(1); // const: useState returns a stable array
  const [search, setSearch] = useState('');

  const filtered = products.filter(
    p => p.name.toLowerCase().includes(search.toLowerCase())
  );

  const paged = filtered.slice((page - 1) * ITEMS_PER_PAGE, page * ITEMS_PER_PAGE);

  function handleSearch(e) {
    const value = e.target.value; // const: used once, no reassignment needed
    setSearch(value);
    setPage(1);
  }

  return (
    <div>
      <input value={search} onChange={handleSearch} />
      <ul>
        {paged.map(p => <li key={p.id}>{p.name}</li>)}
      </ul>
    </div>
  );
}

// ❌ Avoid
for (var i = 0; i < items.length; i++) { ... }

// ✅ Use let for counters
for (let i = 0; i < items.length; i++) { ... }

// ❌ Assuming const prevents mutation
const state = { count: 0 };
state.count = 1; // this works — const only blocks reassignment

// In React this is dangerous: mutating state objects directly breaks rendering
// Always create new objects for state updates:
setState({ ...state, count: 1 }); // ✅

// ❌ Using let unnecessarily signals "I plan to reassign this"
let total = items.reduce((sum, item) => sum + item.price, 0);

// ✅ const is more accurate — the binding never changes
const total = items.reduce((sum, item) => sum + item.price, 0);

// ❌ TDZ — accessing before the const declaration
function setup() {
  console.log(config); // ReferenceError!
  const config = loadConfig();
}

// ✅ Always declare before use
function setup() {
  const config = loadConfig();
  console.log(config);
}
